<div class="grid grid-2"><div class="card"><h3>Manual Attendance</h3><form method="post" action="<?=url('/attendance/store')?>"><?=csrf_field()?><label>Employee</label><select name="employee_id"><?php foreach($employees as $e1):?><option value="<?=e($e1['id'])?>"><?=e($e1['full_name'])?></option><?php endforeach;?></select><label>Date</label><input name="attendance_date" type="date" required><div class="form-row"><div><label>Check In</label><input name="check_in" type="datetime-local"></div><div><label>Check Out</label><input name="check_out" type="datetime-local"></div></div><label>Status</label><select name="status"><option>present</option><option>late</option><option>absent</option><option>leave</option><option>sick</option><option>holiday</option></select><label>Notes</label><textarea name="notes"></textarea><button class="btn btn-primary">Save</button></form></div><div class="card"><h3>Attendance List</h3><table class="table"><tr><th>Date</th><th>Employee</th><th>Status</th></tr><?php foreach($rows as $r):?><tr><td><?=e($r['attendance_date'])?></td><td><?=e($r['full_name'])?></td><td><span class="badge badge-info"><?=e($r['status'])?></span></td></tr><?php endforeach;?></table></div></div>
